import React, { useState } from 'react';

const App = () => {
  const [isSalePrice, setIsSalePrice] = useState(false);
  const originalPrice = 99.99;
  const salePrice = 79.99;

  const togglePrice = () => {
    setIsSalePrice(!isSalePrice);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] rounded p-4 w-96 text-center">
        <div className="flex justify-between items-center mb-4">
          <button className="bg-[#B7D7CD] rounded px-2 py-1 text-sm hover:bg-[#C06C88]" onClick={togglePrice}>Toggle Price</button>
        </div>
        <div className="flex flex-col items-center">
          <div className="flex items-center mb-4">
            <text className="text-[#B7D7CD] mr-2">Original Price:</text>
            <text className="text-2xl font-bold">&#36;{isSalePrice ? salePrice : originalPrice}</text>
          </div>
          <div className="flex items-center">
            <text className="text-[#B7D7CD] mr-2">Sale Price:</text>
            <text className="text-2xl font-bold">&#36;{isSalePrice ? originalPrice : salePrice}</text>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
